mapper.sql:
select , t1.nick_name as userName, concat(t2.icon,t2.title) as assistantTitle, t3.model as model, t3.model_version as modelVersion, t4.icon as modelIcon from gpt_chat t left join gpt_user t1 on t.user_id = t1.id left join gpt_assistant t2 on t.assistant_id = t2.id left join ( select t3_1.chat_id, t3_1.model, t3_1.model_version from gpt_chat_message t3_1 inner join ( select chat_id, max(create_time) as max_time from gpt_chat_message where deleted = 0 and model is not null and model != '' group by chat_id ) t3_2 on t3_1.chat_id = t3_2.chat_id and t3_1.create_time = t3_2.max_time where t3_1.deleted = 0 and t3_1.model is not null and t3_1.model != '' ) t3 on t.id = t3.chat_id left join gpt_model t4 on t3.model = t4.model and t4.deleted = 0 and t4.status = 1
t.deleted = 0 and t.id = #{q.id} and t.user_id = #{q.userId} and (t1.nick_name like concat('%', #{q.userName}, '%') or t1.tel like concat('%', #{q.userName}, '%') ) and t.title like concat('%', #{q.title}, '%') and t.assistant_id = #{q.assistantId} and t.create_time >= #{q.startDate} and t.create_time <= #{q.endDate} ${q.dataScope}
order by t.id desc
